def forward(x):
    x = int(x)
    x = (x ^ ((x << 11) ^ (x >> 21)) ^ ((x << 15) ^ (x >> 17))) & 0xffffffff
    y = (x ^ ((x >> 7) ^ (x << 25)) ^ ((x >> 19) ^ (x << 13))) & 0xffffffff
    return y

# 预计算逆变换（只需运行一次）
def build_inverse():
    # 构建正向变换的 32x32 GF(2) 矩阵并求逆
    M = [[0]*32 for _ in range(32)]
    for j in range(32):
        y = forward(1 << j)
        for i in range(32):
            if (y >> i) & 1:
                M[i][j] = 1

    # 高斯-约当消元求逆
    n = 32
    aug = [row + [1 if i==j else 0 for j in range(n)] for i, row in enumerate(M)]
    # [M | I] → 行变换 → [I | M⁻¹]
    for col in range(n):
        pivot = next(r for r in range(col, n) if aug[r][col])
        aug[col], aug[pivot] = aug[pivot], aug[col]
        for r in range(n):
            if r != col and aug[r][col]:
                for k in range(2*n):
                    aug[r][k] ^= aug[col][k]
    Minv = [row[n:] for row in aug]

    # x = M⁻¹ × y  (在GF(2)上)
    def invert(y):
        y = int(y)
        x = 0
        for i in range(32):
            bit = 0
            for j in range(32):
                if (y >> j) & 1:
                    bit ^= Minv[i][j]
            if bit:
                x |= (1 << i)
        return x
    return invert

# 创建逆函数
invert_forward = build_inverse()

