def generate(MT):
    for i in range(624):
        y = (MT[i] & 0x80000000) + (MT[(i + 1) % 624] & 0x7fffffff)
        MT[i] = MT[(i + 397) % 624] ^ (y >> 1)
        if y & 1:
            MT[i] ^= 2567483520
    return MT
